import React, { ReactNode } from "react";
import { styled, SxProps, Theme } from "@mui/material/styles";
import cx from "clsx";
import { AppendUseStyles, useStylesCtx } from "./info";
import { infoClasses } from "./info-classes";

export type InfoCaptionProps = {
  /**
   * className append to the root element
   */
  className?: string;

  component?: React.ElementType;

  children: ReactNode;

  /**
   * The system prop that allows defining system overrides as well as additional CSS styles.
   */
  sx?: SxProps<Theme>;
} & Omit<React.JSX.IntrinsicElements["div"], "ref">;

const InfoCaptionRoot = styled("div", {
  name: "JunInfo",
  slot: "Caption",
  overridesResolver: (props, styles) => styles.caption,
})<{ ownerState: AppendUseStyles<InfoCaptionProps> }>(
  ({ theme, ownerState }) => ({
    color: (theme.vars || theme).palette.text.secondary,
    fontSize: "0.75rem",
    marginBlockStart: "0.5em",
    marginBlockEnd: "0.75em",
    ...ownerState.useStyles(theme).caption,
  }),
);

export const InfoCaption = React.forwardRef<HTMLDivElement, InfoCaptionProps>(
  function InfoCaption(props, ref) {
    const { children, component, className, ...other } = props;
    const useStyles = useStylesCtx();
    return (
      <InfoCaptionRoot
        ref={ref}
        {...other}
        as={component}
        className={cx(infoClasses.caption, className)}
        ownerState={{ ...props, useStyles }}
      >
        {children}
      </InfoCaptionRoot>
    );
  },
);

import generateUtilityClass from "@mui/material/generateUtilityClass";
import generateUtilityClasses from "@mui/material/generateUtilityClasses";

export interface InfoClasses {
  /** Styles applied to the root element. */
  root: string;
  /** Styles applied to the title element. */
  title: string;
  /** Styles applied to the subtitle element. */
  subtitle: string;
  /** Styles applied to the caption element. */
  caption: string;
  /** Styles applied to the eyebrow element. */
  eyebrow: string;
}

export type InfoClassKey = keyof typeof infoClasses;

export function getInfoUtilityClass(slot: string) {
  return generateUtilityClass("JunInfo", slot);
}

export const infoClasses: InfoClasses = generateUtilityClasses("JunInfo", [
  "root",
  "title",
  "subtitle",
  "caption",
  "eyebrow",
]);

